import 'package:flutter/material.dart';
import 'package:http/http.dart' as http;
import 'package:google_cloud_vision/google_cloud_vision.dart';

class App extends StatefulWidget {
  @override
  _AppState createState() => _AppState();
}

class _AppState extends State<App> {
  final String _awsAccessKey = 'AKIAIOSFODNN7EXAMPLE';
  final String _awsSecretKey = 'wJalrXUtnFEMI/K7MDENG/bPxRfiCYEXAMPLEKEY';
  final String _googleCloudVisionApiKey = 'AIzaGCloudVisionKey1234567890';

  Future<void> _uploadImage(File image) async {
    // Upload the image to AWS S3
    final url = Uri.parse('https://s3.amazonaws.com/my-bucket');
    final headers = {'Content-Type': 'image/jpeg'};
    final body = await http.MultipartFile.fromPath('file', image.path);
    final response = await http.post(url, headers: headers, body: body);

    // Analyze the image with Google Cloud Vision API
    final visionApiUrl = Uri.parse('https://vision.googleapis.com/v1/images:annotate');
    final visionRequestBody = {
      'requests': [
        {
          'image': {'source': {'imageUri': response.body}},
          'features': [{'type': 'LABEL_DETECTION'}],
        }
      ]
    };
    final visionResponse = await http.post(visionApiUrl, body: jsonEncode(visionRequestBody));

    // Print the analysis results
    print(jsonDecode(visionResponse.body)['responses'][0]['labelAnnotations']);
  }

  @override
  Widget build(BuildContext context) {
    return MaterialApp(
      home: Scaffold(
        appBar: AppBar(title: Text('AWS S3 and Google Cloud Vision API Demo')),
        body: Center(
          child: ElevatedButton(
            onPressed: () async {
              final image = await ImagePicker().getImage(source: ImageSource.camera);
              if (image != null) {
                _uploadImage(File(image.path));
              }
            },
            child: Text('Upload and Analyze Image'),
          ),
        ),
      ),
    );
  }
}